const crypto=require('node:crypto');
const {js}=require('/tmp/keys.json');
const row=require('/tmp/gh_row.json')[0];
const AAD=Buffer.from('ivx_owner_variables:v1','utf8');
const key=crypto.createHash('sha256').update(js,'utf8').digest();
try{
  const d=crypto.createDecipheriv('aes-256-gcm',key,Buffer.from(row.value_iv,'base64'));
  d.setAAD(AAD);
  d.setAuthTag(Buffer.from(row.value_tag,'base64'));
  const out=Buffer.concat([d.update(Buffer.from(row.encrypted_value,'base64')),d.final()]).toString('utf8');
  require('fs').writeFileSync('/tmp/ghtok',out);
  const looks=/^(ghp_|github_pat_|gho_|ghu_|ghs_)/.test(out);
  console.log('DECRYPT:OK len:'+out.length+' shape_ok:'+looks+' prefix:'+out.slice(0,4)+'****');
}catch(e){console.log('DECRYPT_FAIL:'+e.message);}
"

